const queries = [];

for (const item of $input.all()) {
  const query = 
    `
    IF EXISTS (SELECT 1 FROM [dbo].[TelegramGroupSource] WHERE Username = N'${item.json['Username']}')
BEGIN
    UPDATE [dbo].[TelegramGroupSource]
    SET 
        GroupType = N'${item.json['GroupType']}',  
        Notes = N'${ item.json["Notes"] }', 
        UpdatedDateTime = GETDATE(),
        SyncStatus = NULL
    WHERE Username = N'${item.json['Username']}';
END
ELSE
BEGIN
    INSERT INTO [dbo].[TelegramGroupSource] (
      Username, 
      GroupType, 
      Notes,
      UpdatedDateTime)
    VALUES (
      N'${item.json['Username']}', 
      N'${item.json['GroupType']}', 
      N'${ item.json["Notes"] }',  
      GETDATE());
END
    `;

  queries.push(query);
}

return {
  query: queries.join('\n') + '\n' + 'SELECT TOP 1 1;'
};

